local pR = require(script.Parent.Symbol)
local t7 = pR.named("Nil")
local t8 = {}
local function rv(pt, rm)
	local t9 = t8[pt]
	if t9 then
		local ta = t9[rm]
		if ta == t7 then
			return true, nil
		end
		if ta ~= nil then
			return true, ta
		end
	else
		t9 = {}
		t8[pt] = t9
	end
	local tb = Instance.new(pt)
	local nx, iM = pcall(function()
		return tb[rm]
	end)
	tb:Destroy()
	if nx then
		if iM == nil then
			t9[rm] = t7
		else
			t9[rm] = iM
		end
	end
	return nx, iM
end
return rv
